### Hashtag/Mention Extraction

Option A: Parse from stored JSON (if available)
```rust
// If entities JSON is stored in metadata column
fn extract_hashtags_from_metadata(storage: &Storage) -> Result<Vec<(String, u64)>> {
    let rows = storage.conn.prepare("SELECT metadata FROM tweets")?;
    let mut counts: HashMap<String, u64> = HashMap::new();
    for row in rows {
        if let Ok(meta) = serde_json::from_str::<Value>(&row.get::<_, String>(0)?) {
            if let Some(hashtags) = meta["entities"]["hashtags"].as_array() {
                for ht in hashtags {
                    if let Some(text) = ht["text"].as_str() {
                        *counts.entry(text.to_lowercase()).or_default() += 1;
                    }
                }
            }
        }
    }
    // Sort by count, take top 20
    let mut sorted: Vec<_> = counts.into_iter().collect();
    sorted.sort_by(|a, b| b.1.cmp(&a.1));
    Ok(sorted.into_iter().take(20).collect())
}
```

Option B: Parse from tweet text using regex
```rust
use regex::Regex;

fn extract_hashtags_from_text(storage: &Storage) -> Result<Vec<(String, u64)>> {
    let hashtag_re = Regex::new(r"#(\w+)")?;
    let mut counts: HashMap<String, u64> = HashMap::new();

    let mut stmt = storage.conn.prepare("SELECT full_text FROM tweets")?;
    for row in stmt.query_map([], |r| r.get::<_, String>(0))? {
        if let Ok(text) = row {
            for cap in hashtag_re.captures_iter(&text) {
                let tag = cap[1].to_lowercase();
                *counts.entry(tag).or_default() += 1;
            }
        }
    }
    // Sort and return top 20
}
```

