fn cmd_stats(cli: &Cli, args: &StatsArgs) -> Result<()> {
    let storage = Storage::open(&cli.db)?;

    // Basic stats (always computed)
    let basic = compute_basic_stats(&storage)?;

    if args.detailed {
        // Show progress for large archives
        if basic.total_tweets > 10_000 {
            eprintln\!("Computing detailed analytics...");
        }

        let temporal = compute_temporal_stats(&storage)?;
        let engagement = compute_engagement_stats(&storage)?;
        let content = compute_content_stats(&storage)?;

        if cli.format.is_json() {
            print_detailed_stats_json(&basic, &temporal, &engagement, &content)?;
        } else {
            print_detailed_stats_text(&basic, &temporal, &engagement, &content)?;
        }
    } else if args.hashtags {
        let content = compute_content_stats(&storage)?;
        print_hashtags(&content.top_hashtags, &cli.format)?;
    } else if args.mentions {
        let content = compute_content_stats(&storage)?;
        print_mentions(&content.top_mentions, &cli.format)?;
    } else {
        // Basic stats only
        print_basic_stats(&basic, &cli.format)?;
    }

    Ok(())
}
```

