#!/bin/bash
set -euo pipefail

# E2E Test Suite for xf stats --detailed
# Tests the full stats analytics pipeline against test archives

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
TEST_ARCHIVE="$PROJECT_ROOT/test-archives/large-archive"
LOG_DIR="$PROJECT_ROOT/test-output"
TIMESTAMP="$(date +%Y%m%d_%H%M%S)"
LOG_FILE="$LOG_DIR/stats_detailed_e2e_$TIMESTAMP.log"

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
NC='\033[0m' # No Color

# Ensure log directory exists
mkdir -p "$LOG_DIR"

# Logging function with timestamps
log() {
    local level="$1"
    shift
    local msg="$*"
    local ts="$(date '+%Y-%m-%d %H:%M:%S.%3N')"
    echo -e "[$ts] [$level] $msg" | tee -a "$LOG_FILE"
}

log_info() { log "INFO" "$*"; }
log_pass() { log "PASS" "${GREEN}$*${NC}"; }
log_fail() { log "FAIL" "${RED}$*${NC}"; }
log_warn() { log "WARN" "${YELLOW}$*${NC}"; }

# Test counter
TESTS_RUN=0
TESTS_PASSED=0
TESTS_FAILED=0

# Run a test and track result
run_test() {
    local name="$1"
    shift
    local cmd="$*"

    ((TESTS_RUN++))
    log_info "Running test: $name"
    log_info "Command: $cmd"

    local start_time=$(date +%s%N)
    local output
    local exit_code=0

    if output=$(eval "$cmd" 2>&1); then
        exit_code=0
    else
        exit_code=$?
    fi

    local end_time=$(date +%s%N)
    local duration_ms=$(( (end_time - start_time) / 1000000 ))

    log_info "Duration: ${duration_ms}ms"
    log_info "Exit code: $exit_code"

    if [ $exit_code -eq 0 ]; then
        log_pass "$name"
        ((TESTS_PASSED++))
    else
        log_fail "$name"
        log_info "Output: $output"
        ((TESTS_FAILED++))
    fi

    echo "$output"
    return $exit_code
}

# Assertion helpers
assert_contains() {
    local haystack="$1"
    local needle="$2"
    local msg="${3:-Output should contain '$needle'}"

    if echo "$haystack" | grep -q "$needle"; then
        log_pass "Assert: $msg"
        return 0
    else
        log_fail "Assert: $msg"
        log_info "Searched for: $needle"
        log_info "In output: $haystack"
        return 1
    fi
}

assert_json_valid() {
    local json="$1"
    local msg="${2:-JSON should be valid}"

    if echo "$json" | jq . >/dev/null 2>&1; then
        log_pass "Assert: $msg"
        return 0
    else
        log_fail "Assert: $msg"
        return 1
    fi
}

assert_performance() {
    local actual_ms="$1"
    local max_ms="$2"
    local msg="${3:-Should complete within ${max_ms}ms}"

    if [ "$actual_ms" -le "$max_ms" ]; then
        log_pass "Assert: $msg (actual: ${actual_ms}ms)"
        return 0
    else
        log_fail "Assert: $msg (actual: ${actual_ms}ms, max: ${max_ms}ms)"
        return 1
    fi
}

