    exit 1
fi

# Test 2: Check sections present
log "[TEST 2] All sections present"
OUTPUT=$(xf doctor --db test-archives/healthy/xf.db 2>&1)
for section in "ARCHIVE" "DATABASE" "INDEX" "PERFORMANCE"; do
    if echo "$OUTPUT" | grep -q "$section"; then
        log "[PASS] Section $section present"
    else
