if echo "$OUTPUT" | jq . >/dev/null 2>&1; then
    log "[PASS] JSON output valid"
else
    log "[FAIL] JSON output invalid"
    exit 1
fi

# Test 4: Performance under threshold
log "[TEST 4] Performance benchmark"
START=$(date +%s)
xf doctor --db test-archives/large/xf.db >/dev/null 2>&1
END=$(date +%s)
DURATION=$((END - START))
if [ "$DURATION" -le 10 ]; then
